args.sparql:
SELECT ?totalAttendance WHERE {
  ?game wdt:P155 ?series .
  ?series wdt:P31 wd:Q524504 .
  ?series wdt:P2893 wd:Q43152 .
  ?game wdt:P1257 ?attendance .
  SERVICE wikibase:group { ?series ?s ?o . }
} GROUP BY ?series ORDER BY DESC(SUM(?attendance)) LIMIT 1 OFFSET 1

SELECT (SUM(?attendance) AS ?totalAttendance) WHERE {
  ?series wdt:P31 wd:Q193325 ;
          wdt:P718 wd:Q43152 .
  ?game wdt:P155 ?series .
  ?game wdt:P1257 ?attendance .
  FILTER (isNumeric(?attendance))
} GROUP BY ?series
ORDER BY DESC(?totalAttendance)
OFFSET 1
LIMIT 1

